/// <summary>
///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
[ExtensionOf(formDataSourcestr(DimensionValueDetails,DimensionAttributeValueLedgerOverride ))]
internal final class ETGDimensionValueDetailsDimAttributesFormDSDMS_Extension
{
}

Method.Source:
/// <summary>
///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = next active();

    ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);

    if(ETGACFParameters::find().EnableDMSIntegration ==NoYes::Yes)
    {
        FormRun formRun = this.formRun();

        FormCheckBoxControl entityListControl = formRun.design().controlName("LedgerOverride_IsSuspended") as FormCheckBoxControl;
        FormDateControl   LedgerOverride_ActiveFrom = formRun.design().controlName("LedgerOverride_ActiveFrom") as FormDateControl;
        FormDateControl   LedgerOverride_ActiveTo = formRun.design().controlName("LedgerOverride_ActiveTo") as FormDateControl;
        FormReferenceGroupControl   LedgerOverride_Owner = formRun.design().controlName("LedgerOverride_Owner") as FormReferenceGroupControl;
        FormDropDialogButtonControl  AddLegalEntityOverride = formRun.design().controlName("AddLegalEntityOverride") as FormDropDialogButtonControl;
        FormButtonControl  RemoveLegalEntityOverride = formRun.design().controlName("RemoveLegalEntityOverride") as FormButtonControl;

        if (entityListControl)
        {
            entityListControl.enabled(false);
        }
        else
        {
            entityListControl.enabled(true);
        }
        if(LedgerOverride_ActiveFrom)
        {
            LedgerOverride_ActiveFrom.enabled(false);
        }
        else
        {
            LedgerOverride_ActiveFrom.enabled(true);
        }
        if(LedgerOverride_ActiveTo)
        {
            LedgerOverride_ActiveTo.enabled(false);
        }
        else
        {
            LedgerOverride_ActiveTo.enabled(true);
        }
        if(LedgerOverride_Owner)
        {
            LedgerOverride_Owner.enabled(false);
            LedgerOverride_Owner.allowEdit(false);
        }
        else
        {
            LedgerOverride_Owner.enabled(true);
            LedgerOverride_Owner.allowEdit(true);
        }

        if(AddLegalEntityOverride)
        {
            AddLegalEntityOverride.enabled(false);
        }
        else
        {
            AddLegalEntityOverride.enabled(true);
        }
        if(RemoveLegalEntityOverride)
        {
            RemoveLegalEntityOverride.enabled(false);
        }
        else
        {
            RemoveLegalEntityOverride.enabled(true);
        }
    }

    return ret;

}
